import React, { useEffect, useState } from "react";
import axios from "axios";
import AdminNav from "./AdminNav";

const Hospitals = () => {
  const [items, setItems] = useState([]);
  const [error, setError] = useState("");
  const apiURL = process.env.REACT_APP_API_URL || "http://localhost:8000";

  useEffect(() => {
    const run = async () => {
      try {
        const raw = localStorage.getItem("adminJwt");
        if (!raw) { setError("Missing admin token"); return; }
        const { token } = JSON.parse(raw);
        const res = await axios.get(`${apiURL}/api/admin/hospitals?page=1&limit=50`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (res.data && res.data.success) setItems(res.data.data);
        else setError(res.data.error || "Failed to load hospitals");
      } catch (err) {
        setError("Network or authorization error");
      }
    };
    run();
  }, [apiURL]);

  return (
    <div className="max-w-6xl mx-auto mt-10 p-6 border rounded">
      <h2 className="text-2xl font-semibold mb-4">Hospitals</h2>
      <AdminNav />
      {error && <div className="text-red-600 mb-3">{error}</div>}
      <div className="overflow-x-auto">
        <table className="min-w-full text-sm">
          <thead>
            <tr className="text-left">
              <th className="p-2">Name</th>
              <th className="p-2">Email</th>
              <th className="p-2">Phone</th>
              <th className="p-2">Verified</th>
              <th className="p-2">Phone Verified</th>
            </tr>
          </thead>
          <tbody>
            {items.map((u) => (
              <tr key={u._id}>
                <td className="p-2">{u.name}</td>
                <td className="p-2">{u.email}</td>
                <td className="p-2">{u.phoneNumber || "-"}</td>
                <td className="p-2">{String(u.verified)}</td>
                <td className="p-2">{String(u.phoneVerified)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Hospitals;
